import { supabase } from '@/lib/supabase'
import { NextResponse } from 'next/server'

export const dynamic = 'force-dynamic'

export async function GET() {
    try {
        const { data, error } = await supabase.from('catalog_items').select('*').limit(1)

        if (error) {
            return NextResponse.json({ status: 'error', code: error.code, message: error.message }, { status: 500 })
        }

        return NextResponse.json({
            status: 'success',
            data: data || []
        })
    } catch (error: any) {
        return NextResponse.json({ status: 'error', message: error.message }, { status: 500 })
    }
}

import { supabase } from '@/lib/supabase';
import { NextResponse } from 'next/server';

export const dynamic = 'force-dynamic';

export async function GET() {
    try {
        // 1. Create site_settings table if it doesn't exist (using JS as a check)
        // Note: Real table creation should be done in Supabase SQL Editor, 
        // but we can check if it exists or try a simple operation.

        const { error: checkError } = await supabase
            .from('site_settings')
            .select('key')
            .limit(1);

        if (checkError && checkError.code === '42P01') { // Table doesn't exist
            return NextResponse.json({
                status: 'error',
                message: 'Table "site_settings" does not exist. Please run this in your Supabase SQL Editor: CREATE TABLE site_settings (key TEXT PRIMARY KEY, value JSONB);'
            }, { status: 400 });
        }

        // 2. Ensure basic keys exist
        const keys = ['catalog_categories', 'hero_images', 'hero_title', 'hero_description'];
        for (const key of keys) {
            const { data } = await supabase.from('site_settings').select('*').eq('key', key).single();
            if (!data) {
                let defaultValue: any = "";
                if (key === 'catalog_categories') defaultValue = ['Lifestyle', 'Accessories', 'Design', 'Vintage'];
                if (key === 'hero_images') defaultValue = ['', '', ''];

                await supabase.from('site_settings').insert({ key, value: defaultValue });
            }
        }

        return NextResponse.json({ status: 'success', message: 'Database schema and settings verified.' });
    } catch (e: any) {
        return NextResponse.json({ status: 'error', message: e.message }, { status: 500 });
    }
}

import { supabase } from '@/lib/supabase';
import { NextResponse } from 'next/server';

export const dynamic = 'force-dynamic';

export async function GET() {
    try {
        // Since I can't run raw SQL easily via the client in some configs, 
        // I'll try to use the rpc if available, but usually adding columns is better via dashboard.
        // However, I'll try to use a trick if the user has enabled it, or just advise them.

        // Actually, I'll just check if the column exists first.
        const { data, error } = await supabase
            .from('catalog_items')
            .select('gallery')
            .limit(1);

        if (error && error.code === '42703') { // Column does not exist
            return NextResponse.json({
                error: "Gallery column missing. Please run the following SQL in Supabase Editor: ALTER TABLE catalog_items ADD COLUMN gallery TEXT[] DEFAULT '{}';"
            }, { status: 400 });
        }

        return NextResponse.json({ status: "Gallery column exists" });
    } catch (e: any) {
        return NextResponse.json({ error: e.message }, { status: 500 });
    }
}

